package Synergech;
import java.util.*;
public class BiggestOfTwoNumbers {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		Scanner s=new Scanner(System.in);
		int n=s.nextInt();
		int m=s.nextInt();
		if(n>m) {
			System.out.print("N is Greater"+n);
		}else {
			System.out.print("M is Greater"+m);
		}
	}

}
